                id = "0", speaker = "Henwick",
                text = "*(A dusty, mild man standing very upright on a library shelf, between two actual books, with a catalogue-tag tied to his toe.)* Don't reshelve me. *(he says it wearily, before you can speak.)* Everyone tries to reshelve me. I am, technically, currently, *correctly* shelved. Section H, \"Histories, Personal, Unreliable.\" *(he sighs.)* Sixty years ago a junior cataloguer — gods rest his thorough little soul — recorded me as a *primary source* rather than a *person*, accessioned me into the collection, and assigned me a *call number.* And Candlekeep, Returned, does not *deaccession.* It is easier to amend the laws of the gods than to remove a thing from this catalogue once it's been *entered.* So. Here I stand. Henwick. Call number HEN-440.7. A man, legally, a *book.*",
                autoNextNodeId = "1",
                onEnter = new[] { new FlagClause { key = "npc.henwick_met", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "1", speaker = "Henwick",
                text = "*(He adjusts his catalogue-tag with dignity.)* You'd think it a tragedy. *(mildly.)* It has its compensations. I am *very* well preserved — the climate controls are excellent. I am *consulted* — scholars come to read me, which is more attention than most men get. And I am, by the strictest reading of Candlekeep law, *immortal*, because the catalogue is eternal and I am *in* it. *(a small, dusty smile.)* The harvest cannot take me, you see. The Wall cannot file me. I'm already *filed* — correctly, here, in Section H. The one soul in the Realms the death-cult cannot touch, because a clerical error sixty years ago made me a *reference work.* *(he peers at you.)* You're a Returned. A soul the *other* archive couldn't keep. We're cousins, you and I — both saved by a *filing* the system can't undo. Only yours was an escape, and mine was an *accession.* I do envy you the legs.",
                choices = new[]
                {
                    new DialogueChoice { text = "[INSIGHT 14] \"You stay on the shelf because down there, you'd be a lonely old man — but *here*, you're consulted, preserved, needed. The misfiling gave you the one thing life didn't: a *place.*\"", nextNodeId = "place", checkAbility = Ability.Wisdom, checkDC = 14, failNodeId = "mild" },
                    new DialogueChoice { text = "\"I could get you deaccessioned. Restored to a person. Would you even want it?\"", nextNodeId = "deaccession" },
                    new DialogueChoice { text = "\"You're proof the harvest can be *out-filed*. The Wall files the forgotten — but a thing properly *catalogued* can't be unmade. That's a weapon.\"", nextNodeId = "weapon", effects = new[] { new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 3 } } },
                    new DialogueChoice { text = "\"Sixty years a book. What have you learned, HEN-440.7, that the histories around you haven't?\"", nextNodeId = "learned" },
                }
            });

            g.nodes.Add(new DialogueNode
            {
                id = "place", speaker = "Henwick",
                text = "*(The dusty composure softens.)* ...A *place.* *(quietly.)* You've read me better than the scholars do. *(he looks down the long shelf.)* Yes. Before the misfiling, I was a *minor* historian, unmarried, unremarkable, the sort of man who dies and leaves a thin volume and a thinner estate and no one to mind either. *(he touches his catalogue-tag.)* And then a junior clerk made his thorough little error, and *suddenly* — I was *kept.* Climate-controlled. Consulted. *Necessary.* I had spent sixty years *failing* to matter, and a *mistake* did in an afternoon what my whole life couldn't: it filed me somewhere I'd be *missed* if I went absent. *(a watery smile.)* So no, Returned. Don't reshelve me. Don't restore me. The shelf is the only place I was ever *wanted.* It took being mistaken for a book to make a forgettable man *unforgettable.* I'd not trade it for legs and loneliness. Not for anything. Section H is *home.*",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.henwick_belongs", op = FlagOp.SetTrue }, new FlagClause { key = "companion.garrow.approval", op = FlagOp.AddInt, amount = 3 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "deaccession", speaker = "Henwick",
                text = "*(He recoils, gripping the shelf-edge.)* Deaccessioned. *(with quiet horror.)* You'd — restore me to a *person.* A free, *mortal*, *forgettable* person. *(he shudders.)* And then the harvest could take me, and the Wall could file me, and when I died — soon, I'm seventy-four — I'd be *forgotten*, like the minor historian I was always going to be, instead of *preserved* forever as HEN-440.7. *(he shakes his head, firm.)* No. *No.* You mean it kindly, and it is the cruelest mercy ever offered me. *(quietly.)* The misfiling is the only thing standing between Henwick and the nothing. Leave me misfiled, Returned. Leave me wrong. Being *wrongly kept* is infinitely better than being *rightly lost.* That's the whole secret of this place — and, I begin to suspect, of you.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.henwick_refuses", op = FlagOp.SetTrue } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "weapon", speaker = "Henwick",
                text = "*(His mild eyes sharpen with sudden scholarly excitement.)* A *weapon.* *(he leans forward on his shelf.)* You've seen it. The principle. *(rapidly, the historian waking.)* The Wall files the *forgotten* — souls with no record, no claim, no entry. The nothing *needs* the nothing; it can only take what isn't *kept somewhere else.* But a soul *properly catalogued* — entered, called-numbered, *referenced* — cannot be unmade, because to unmake it would create a *gap in the record*, and the universe, Returned, *abhors a dangling reference* even more than a vacancy. *(he's almost vibrating.)* That's why *I* can't be harvested. And that's how you fight the Wall — not by *freeing* the Faithless, but by *cataloguing* them. Enter them somewhere. Give them a call number. A name in a ledger the world can't deaccession. *(quietly, urgent.)* Tell the child with the list. Tell the auctioneer with the ledger. They're not *mourning* the forgotten. They're *out-filing the Wall.* And it's *working.* Henwick, HEN-440.7, mild and misfiled, has been the proof for sixty years.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.henwick_the_principle", op = FlagOp.SetTrue }, new FlagClause { key = "act2.cataloguing_defeats_the_wall", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 4 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "learned", speaker = "Henwick",
                text = "*(He considers, between his two book-neighbors.)* Sixty years a book. *(slowly.)* I've learned what the histories around me can't say, because they're *finished* and I'm still *accruing.* *(he taps a neighbor volume.)* This one's a chronicle of a war. Closed. Certain. Knows exactly how it ended. *(he taps his own chest.)* But *I* don't know how I end, because I'm not *done* — I'm a history still being *lived*, shelved among histories already *concluded.* *(quietly, profoundly.)* And what I've learned, Returned, sixty years among the finished, is this: *the certain ones are the dead ones.* A thing that knows exactly how its story goes is a thing whose story is *over.* The only *living* book on this shelf is the one that doesn't know its own ending. *(he looks at you, the un-finished soul.)* Which makes *you* the most alive thing to walk these stacks in an age. Stay unfinished, Returned. It's the only immortality that's actually worth having. The other kind — *(he gestures at the closed histories)* — is just a very tidy grave.",
                autoNextNodeId = "close",
                onEnter = new[] { new FlagClause { key = "npc.henwick_wisdom", op = FlagOp.SetTrue }, new FlagClause { key = "companion.naeve.approval", op = FlagOp.AddInt, amount = 2 } },
            });

            g.nodes.Add(new DialogueNode
            {
                id = "mild", speaker = "Henwick",
                text = "*(He smiles, dusty and unbothered.)* A pleasant theory. *(mildly.)* But I'm simply a misfiled man making the best of an immortal clerical error. No deeper pathos required. *(he adjusts his tag.)* Do mind the shelf on your way. And if you see a junior cataloguer, send him along — I've a *correction* to *not* request.",
                autoNextNodeId = "close",
            });

            g.nodes.Add(new DialogueNode
            {
                id = "close", speaker = "Henwick",
                text = "*(He settles back between his book-neighbors, HEN-440.7, mild and misfiled and unforgettable — a man saved from oblivion by a mistake, who would not be corrected for the world — and you carry his principle down toward the Sealed Stacks like a key: *the Wall can only take what nothing else has kept.*)*",
            });

            NpcKeepHenwickDialogue = g;
        }
    }
}
